$files = @(
  @{ path = "packages/langchain/src/index.ts"; b64 = "" }
  @{ path = "packages/langchain/src/types.ts"; b64 = "" }
  @{ path = "packages/langchain/src/tools.ts"; b64 = "" }
  @{ path = "packages/langchain/src/graph.ts"; b64 = "" }
  @{ path = "packages/langchain/test/langchain.test.ts"; b64 = "" }
  @{ path = "packages/langchain/examples/langgraph-demo.ts"; b64 = "" }
  @{ path = "packages/langchain/examples/tool-runner-demo.ts"; b64 = "" }
  @{ path = "packages/langchain/package.json"; b64 = "" }
  @{ path = "packages/langchain/tsconfig.json"; b64 = "" }
  @{ path = "packages/langchain/README.md"; b64 = "" }
)
foreach ($file in $files) {
    $target = [System.IO.Path]::GetFullPath([System.IO.Path]::Combine($PWD, $file.path))
    $dir = [System.IO.Path]::GetDirectoryName($target)
    if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
    [System.IO.File]::WriteAllBytes($target, [System.Convert]::FromBase64String($file.b64))
    Write-Host "wrote $($file.path)"
}
Write-Host "Done."
